package com.chimera.rpg.entity\n\nimport androidx.compose.runtime.Composable\nimport androidx.compose.runtime.LaunchedEffect\nimport androidx.compose.runtime.mutableStateOf\nimport androidx.compose.runtime.remember\nimport androidx.compose.ui.Modifier\nimport androidx.compose.ui.geometry.Offset\nimport androidx.compose.ui.graphics.Color\nimport androidx.compose.ui.graphics.drawscope.Stroke\nimport androidx.compose.ui.graphics.drawscope.drawIntoCanvas\nimport androidx.compose.ui.platform.LocalDensity\nimport androidx.compose.ui.unit.Dp\nimport androidx.compose.ui.unit.dp\nimport com.chimera.rpg.R\nimport kotlin.math.cos\nimport kotlin.math.sin\n\n/**\n * Enemy entity with simple combat AI.\n *\n * Enemies patrol an area and engage targets within attack range.\n * They flee when critically low on HP.\n */\nclass Enemy(\n    name: String,\n    maxHp: Int,\n    maxMp: Int,\n    str: Int,\n    agi: Int,\n    int: Int,\n    override val iconResId: Int = R.drawable.ic_enemy,\n    onDie: (() -> Unit)? = null\n) : Entity(name, maxHp, maxMp, str, agi, int, iconResId, onDie) {\n\n    enum class State { PATROL, CHASE, FLEE, COOLDOWN }\n\n    var state by mutableStateOf(State.PATROL)\n        private set\n    var attackCooldown by mutableStateOf(0f)\n        private set\n    var patrolAngle by mutableStateOf(0f)\n        private set\n\n    /** Range at which the enemy engages a target. */\n    val engagementRange = 150f\n    /** Range at which the enemy flees. */\n    val fleeRange = maxHp * 0.35f\n    /** Cooldown before next action. */\n    val actionCooldown = 1.5f\n\n    /**\n     * Updates enemy state based on target position and distance.\n     * [targetPos] is in Canvas pixels.\n     * [dt] is delta time in seconds.\n     */\n    fun update(targetPos: Offset, dt: Float, selfPos: Offset) {\n        val distToTarget = (Offset(targetPos.x - selfPos.x, targetPos.y - selfPos.y).run { (x * x + y * y).pow(0.5f) })\n\n        attackCooldown = max(0f, attackCooldown - dt)\n\n        state = when {\n            isDead -> State.COOLDOWN\n            currentHp < fleeRange -> State.FLEE\n            distToTarget < engagementRange && attackCooldown <= 0f -> State.CHASE\n            else -> State.PATROL\n        }\n\n        when (state) {\n            State.PATROL -> {\n                patrolAngle = (patrolAngle + 0.3f * dt) % 360f\n            }\n            State.CHASE -> {\n                // Face target\n            }\n            State.FLEE -> {\n                // Move away from target\n                patrolAngle = (patrolAngle - 1.2f * dt) % 360f\n            }\n            State.COOLDOWN -> {\n                // Reset after a short pause\n                actionCooldown = 2f\n                if (attackCooldown <= 0f) state = State.PATROL\n            }\n        }\n    }\n\n    /** Attacks the target, consuming MP and returning damage. */\n    fun attack(): Float {\n        if (attackCooldown > 0 || !consumeMp(3)) return 0f\n        attackCooldown = actionCooldown\n        return spellDamageMultiplier(0.9f)\n    }\n\n    /**\n     * Renders the enemy as a stylized creature with state-dependent color.\n     */\n    @Composable\n    fun render(modifier: Modifier = Modifier, position: Offset = Offset.Zero) {\n        val radius = with(LocalDensity.current) { (modifier.size?.width ?: 50.dp).toPx() / 2 }\n        val baseColor = when (state) {\n            State.PATROL -> Color(0xFF884EA0) // purple\n            State.CHASE -> Color(0xFFE74C3C) // red\n            State.FLEE -> Color(0xFFF39C12) // orange\n            State.COOLDOWN -> Color(0xFF95A5A6) // gray\n        }\n        val bobY = sin(patrolAngle * 0.05f) * 4.dpToPx()\n\n        Canvas(\n            modifier = modifier\n        ) { drawScope ->\n            drawIntoCanvas { canvas ->\n                canvas.save()\n                canvas.translate(position.x + radius, position.y + radius + bobY)\n\n                // Body\n                drawCircle(\n                    color = baseColor,\n                    radius = radius,\n                    style = Stroke(width = 2.dpToPx())\n                )\n\n                // Eyes\n                val eyeSpread = 0.35f\n                drawCircle(\n                    color = Color.White,\n                    radius = 3.dpToPx(),\n                    center = Offset(-radius * eyeSpread, -radius * 0.1f)\n                )\n                drawCircle(\n                    color = Color.White,\n                    radius = 3.dpToPx(),\n                    center = Offset(radius * eyeSpread, -radius * 0.1f)\n                )\n                drawCircle(\n                    color = Color.Black,\n                    radius = 1.5f.dpToPx(),\n                    center = Offset(-radius * eyeSpread, -radius * 0.1f)\n                )\n                drawCircle(\n                    color = Color.Black,\n                    radius = 1.5f.dpToPx(),\n                    center = Offset(radius * eyeSpread, -radius * 0.1f)\n                )\n\n                // HP bar\n                drawRoundRect(\n                    color = Color.Black.copy(alpha = 0.6f),\n                    topLeft = Offset(-radius, radius + 10.dpToPx()),\n                    size = androidx.compose.ui.unit.Size(radius * 2, 6.dpToPx()),\n                    cornerRadius = androidx.compose.ui.unit.CornerRadius(3.dpToPx())\n                )\n                drawRoundRect(\n                    color = if (currentHp < maxHp * 0.3f) Color.Red else Color.Green,\n                    topLeft = Offset(-radius, radius + 10.dpToPx()),\n                    size = androidx.compose.ui.unit.Size(radius * 2 * (currentHp / maxHp).coerceIn(0f, 1f), 6.dpToPx()),\n                    cornerRadius = androidx.compose.ui.unit.CornerRadius(3.dpToPx())\n                )\n\n                // Name tag\n                drawContext.canvas.nativeCanvas.apply {\n                    val paint = android.graphics.Paint().apply {\n                        color = android.graphics.Color.WHITE\n                        textSize = 30f\n                        textAlign = android.graphics.Paint.Align.CENTER\n                    }\n                    drawText(name, 0f, -radius - 6.dpToPx(), paint)\n                }\n\n                canvas.restore()\n            }\n        }\n    }\n}\n\nprivate val Float.dpToPx: Float\n    get() = this * 1.5f\n\n/** Preview showing an enemy in patrol state. */\n@Preview\n@Composable\nprivate fun Enemy_Patrol_Preview() {\n    val enemy = remember {\n        Enemy(\n            name = \"Goblin\",\n            maxHp = 30,\n            maxMp = 15,\n            str = 6,\n            agi = 8,\n            int = 2\n        )\n    }\n    Box(modifier = Modifier.size(100.dp)) {\n        enemy.render()\n    }\n}\n\n/** Preview showing an enemy chasing. */\n@Preview\n@Composable\nprivate fun Enemy_Chase_Preview() {\n    val enemy = remember {\n        Enemy(\n            name = \"Orc\",\n            maxHp = 80,\n            maxMp = 40,\n            str = 12,\n            agi = 6,\n            int = 4\n        )\n    }\n    LaunchedEffect(Unit) {\n        enemy.takeDamage(50)\n    }\n    Box(modifier = Modifier.size(100.dp)) {\n        enemy.render()\n    }\n}"}}